INSERT INTO products (id, name, description, price, stock, image_url, sales_count, is_featured, created_at) VALUES
(1, 'ノイズキャンセリングワイヤレスイヤホン', '没入感を高める高性能ノイズキャンセリング搭載。クリアな高音質で音楽も通話も快適に楽しめる。', 8980, 150, 'product01.jpg', 123, TRUE, '2025-06-25 10:00:00'),
(2, '極上肌触りマイクロファイバーブランケット', 'ふわふわでとろけるような肌触りのマイクロファイバー製ブランケット。寒い季節に手放せない一枚。', 2980, 200, 'product02.jpg', 87, FALSE, '2025-06-26 11:30:00'),
(3, '超軽量コンパクト折りたたみ傘', 'カバンにすっぽり収まる超軽量設計。急な雨にもスマートに対応できる晴雨兼用傘。', 1980, 180, 'product03.jpg', 98, FALSE, '2025-06-26 14:00:00'),
(4, '姿勢改善ノートPCスタンド', '人間工学に基づいたデザインで、デスクワーク中の姿勢を快適にサポート。放熱効果も抜群。', 3500, 120, 'product04.jpg', 64, TRUE, '2025-06-27 09:15:00'),
(5, '北欧デザインセラミックマグカップ', '食卓を彩るモダンな北欧デザインのマグカップ。温かい飲み物をより美味しく。', 1700, 8, 'product05.jpg', 152, FALSE, '2025-06-27 16:45:00'),
(6, 'お部屋に癒しミニ観葉植物セット', '手軽にグリーンを楽しめる手のひらサイズの観葉植物3種セット。初心者にもおすすめです。', 4500, 90, 'product06.jpg', 43, TRUE, '2025-06-28 10:30:00'),
(7, '静音スリムポータブル扇風機', '夏の暑さ対策に必須。静かでパワフルな風を送る、持ち運び便利なUSB充電式扇風機。', 2480, 300, 'product07.jpg', 205, FALSE, '2025-06-28 13:00:00'),
(8, '本場イタリア産パスタセット', '厳選された小麦で作られた本格イタリアンパスタのギフトセット。', 3980, 0, 'product08.jpg', 32, FALSE, '2025-06-29 09:00:00'),
(9, '高精度タッチペン（スタイラスペン）', 'タブレットやスマートフォンでの繊細な操作に。イラストや手書きメモもスムーズに。', 2800, 110, 'product09.jpg', 57, TRUE, '2025-06-29 11:45:00'),
(10, '天然エッセンシャルオイルアロマキャンドル', '心安らぐ香りでリラックスタイムを演出。天然素材を使用した安全なアロマキャンドル。', 1800, 160, 'product10.jpg', 74, FALSE, '2025-06-30 14:20:00'),
(11, 'オンオフ兼用アナログ腕時計', 'ビジネスにもカジュアルにも合う、シンプルで飽きのこないデザイン。', 9800, 60, 'product11.jpg', 29, FALSE, '2025-06-30 17:00:00'),
(12, '厳選ドリップコーヒー飲み比べセット', '世界各地の厳選豆を使用したドリップコーヒー。自宅で手軽に専門店の味を楽しめます。', 5500, 80, 'product12.jpg', 38, TRUE, '2025-07-01 09:30:00'),
(13, 'カチカチしない静音ワイヤレスマウス', 'クリック音が気にならない静音設計。オフィスや図書館でも周りを気にせず使えます。', 1480, 220, 'product13.jpg', 135, FALSE, '2025-07-01 12:10:00'),
(14, '髪と地球に優しいボタニカルシャンプー詰替用', '植物由来成分で優しく洗い上げるシャンプーの大容量詰め替えパック。環境にも配慮しています。', 1600, 190, 'product14.jpg', 101, FALSE, '2025-07-02 10:50:00'),
(15, '彩り豊か旬のフルーツ詰め合わせ', 'この時期一番美味しい旬のフルーツを厳選。大切な方への贈り物に最適なギフトセットです。', 6500, 50, 'product15.jpg', 24, TRUE, '2025-07-02 15:30:00'),
(16, '超吸水・高耐久性キッチンペーパー', '料理の下準備からキッチン周りの掃除まで、マルチに活躍する厚手で丈夫なキッチンペーパー。', 800, 350, 'product16.jpg', 255, FALSE, '2025-07-03 09:00:00'),
(17, '高機能キッチンペーパー（業務用）', '飲食店のプロも納得の吸収力と耐久性。油汚れもしっかり拭き取る大判キッチンペーパー。', 1650, 200, 'product16.jpg', 104, FALSE, '2025-07-03 11:00:00'),
(18, '完熟フルーツ贅沢セット', 'とれたて新鮮！農家直送の甘みたっぷり完熟フルーツ。大切な人への贈り物にも最適。', 7200, 40, 'product15.jpg', 21, TRUE, '2025-07-03 14:00:00'),
(19, 'ヘアサロン専売シャンプー（詰替用）', 'プロが認めた美しい髪へ導くシャンプー。お得な詰め替え用で毎日サロン級の仕上がり。', 1800, 170, 'product14.jpg', 92, FALSE, '2025-07-03 16:00:00'),
(20, 'エルゴノミクス静音マウス', '手にフィットするエルゴノミクスデザイン。クリック音を抑えた静音設計で長時間の作業も快適。', 1600, 210, 'product13.jpg', 128, FALSE, '2025-07-04 09:30:00'),
(21, '本格派ドリップコーヒー（深煎り）', '芳醇な香りと深いコクが特徴の深煎りドリップコーヒー。忙しい朝を贅沢な時間に変える一杯。', 5200, 75, 'product12.jpg', 34, FALSE, '2025-07-04 11:00:00'),
(22, 'シンプルモダンアナログ腕時計', 'どんなスタイルにも合わせやすい、洗練されたデザインのアナログ腕時計。普段使いに最適。', 8500, 55, 'product11.jpg', 31, TRUE, '2025-07-04 13:00:00'),
(23, '癒しの香りアロマキャンドルセット', 'ラベンダー、ローズ、シトラスの3種の香りが楽しめるアロマキャンドル。心身のリラックスに。', 2000, 150, 'product10.jpg', 68, FALSE, '2025-07-04 15:00:00'),
(24, 'iPad対応高感度スタイラスペン', 'iPadでのイラスト作成やノート取りに最適。充電不要でいつでも使える高感度タッチペン。', 2900, 105, 'product09.jpg', 53, FALSE, '2025-07-05 10:00:00'),
(25, '有機栽培パスタ＆野菜ギフト', 'イタリアの有機農場で育った小麦を使ったパスタと、こだわり野菜のセット。健康志向の方へ。', 4200, 65, 'product08.jpg', 28, TRUE, '2025-07-05 12:00:00'),
(26, 'オフィス向け小型扇風機', 'デスクに置けるコンパクトサイズの扇風機。USB給電でPCから電源供給可能。静音設計で仕事の邪魔にならない。', 2300, 280, 'product07.jpg', 73, FALSE, '2025-07-05 14:00:00'),
(27, 'テラリウム作成キット（観葉植物付）', '自分だけの小さな緑の空間が作れるキット。土や石、ミニ観葉植物が全て揃っています。', 4800, 85, 'product06.jpg', 45, FALSE, '2025-07-05 16:00:00'),
(28, '保温性抜群マグカップ', 'オフィスでも自宅でも大活躍。温かい飲み物も冷たい飲み物も長時間キープできる高機能マグカップ。', 1500, 240, 'product05.jpg', 69, FALSE, '2025-07-06 09:00:00'),
(29, 'デスクワーク快適ノートPCスタンド', '目線が上がり首や肩への負担を軽減。折りたたみ式で持ち運びにも便利なノートパソコンスタンド。', 3600, 115, 'product04.jpg', 61, TRUE, '2025-07-06 11:00:00'),
(30, '晴雨兼用自動開閉折りたたみ傘', 'ボタン一つで開閉できる便利な自動開閉式。晴れの日も雨の日もこれ一本で安心。', 2200, 170, 'product03.jpg', 95, FALSE, '2025-07-06 13:00:00'),
(31, 'あったかふわふわブランケット', '冷え込む夜に最適。全身を温かく包み込むブランケット。', 3200, 190, 'product02.jpg', 78, TRUE, '2025-07-07 09:00:00'),
(32, 'スポーツ向け完全ワイヤレスイヤホン', '激しい運動でも外れにくいフィット感。IPX7防水で汗や雨にも強いスポーツ専用イヤホン。', 9500, 140, 'product01.jpg', 118, FALSE, '2025-07-07 11:00:00'),
(33, '大判あったかブランケット', 'ソファでくつろぎタイムに最適。二人でゆったり使える大判サイズの肌触りの良いブランケット。', 3100, 180, 'product02.jpg', 68, FALSE, '2025-07-07 13:00:00'),
(34, 'コンパクト収納折りたたみ傘', 'カバンに常備できるコンパクトさ。軽量で持ち運びやすく、突然の雨にも対応できる折りたたみ傘。', 1800, 175, 'product03.jpg', 88, TRUE, '2025-07-07 15:00:00'),
(35, '人間工学ノートパソコンスタンド', '姿勢を改善し、快適な作業環境を提供するノートパソコンスタンド。放熱性にも優れています。', 3500, 120, 'product04.jpg', 62, FALSE, '2025-07-07 17:00:00'),
